// POST /token - Token endpoint
// Supports grant_type: authorization_code and refresh_token
app.post('/token', (req, res) => {
  const { grant_type } = req.body;

  // Extract client credentials (support both body and Basic auth)
  let client_id, client_secret;

  const authHeader = req.headers['authorization'];
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.slice(6), 'base64').toString('utf-8');
    const parts = decoded.split(':');
    client_id = decodeURIComponent(parts[0]);
    client_secret = decodeURIComponent(parts.slice(1).join(':'));
  } else {
    client_id = req.body.client_id;
    client_secret = req.body.client_secret;
  }

  // Validate client credentials
  if (!client_id || !client_secret) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Client authentication required. Provide client_id and client_secret.'
    });
  }

  const client = clients[client_id];
  if (!client || client.client_secret !== client_secret) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Invalid client credentials'
    });
  }

  if (grant_type === 'authorization_code') {
    return handleAuthorizationCodeGrant(req, res, client);
  } else if (grant_type === 'refresh_token') {
    return handleRefreshTokenGrant(req, res, client);
  } else {
    return res.status(400).json({
      error: 'unsupported_grant_type',
      error_description: 'Supported grant types: authorization_code, refresh_token'
    });
  }
});

function handleAuthorizationCodeGrant(req, res, client) {
  const { code, redirect_uri } = req.body;

  if (!code) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'Authorization code is required'
    });
  }

  if (!redirect_uri) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'redirect_uri is required'
    });
  }

  const authCode = authorizationCodes[code];

  if (!authCode) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Invalid or expired authorization code'
    });
  }

  // Verify the code hasn't expired
  if (authCode.expiresAt < Date.now()) {
    delete authorizationCodes[code];
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code has expired'
    });
  }

  // Verify the code was issued to the same client
  if (authCode.client_id !== client.client_id) {
    delete authorizationCodes[code];
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code was not issued to this client'
    });
  }

  // Verify redirect_uri matches
  if (authCode.redirect_uri !== redirect_uri) {
    delete authorizationCodes[code];
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'redirect_uri does not match the one used in the authorization request'
    });
  }

  // Authorization code is single-use: delete it
  delete authorizationCodes[code];

  // Generate tokens
  const access_token = generateAccessToken();
  const refresh_token = generateRefreshToken();
  const expires_in = 3600; // 1 hour

  accessTokens[access_token] = {
    client_id: client.client_id,
    user: authCode.user,
    scope: authCode.scope,
    expiresAt: Date.now() + (expires_in * 1000)
  };

  refreshTokens[refresh_token] = {
    client_id: client.client_id,
    user: authCode.user,
    scope: authCode.scope
  };

  // Set Cache-Control and Pragma headers as required by OAuth 2.0 spec
  res.set('Cache-Control', 'no-store');
  res.set('Pragma', 'no-cache');

  return res.json({
    access_token,
    token_type: 'Bearer',
    expires_in,
    refresh_token,
    scope: authCode.scope
  });
}

function handleRefreshTokenGrant(req, res, client) {
  const { refresh_token, scope } = req.body;

  if (!refresh_token) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'refresh_token is required'
    });
  }

  const storedRefreshToken = refreshTokens[refresh_token];

  if (!storedRefreshToken) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Invalid refresh token'
    });
  }

  // Verify the refresh token was issued to the same client
  if (storedRefreshToken.client_id !== client.client_id) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Refresh token was not issued to this client'
    });
  }

  // Optionally narrow the scope (but cannot broaden)
  let tokenScope = storedRefreshToken.scope;
  if (scope) {
    const requestedScopes = scope.split(' ');
    const originalScopes = storedRefreshToken.scope.split(' ');
    const isSubset = requestedScopes.every(s => originalScopes.includes(s));
    if (!isSubset) {
      return res.status(400).json({
        error: 'invalid_scope',
        error_description: 'Requested scope exceeds the scope of the original grant'
      });
    }
    tokenScope = scope;
  }

  // Rotate refresh token (invalidate old one, issue new one)
  delete refreshTokens[refresh_token];

  const new_access_token = generateAccessToken();
  const new_refresh_token = generateRefreshToken();
  const expires_in = 3600;

  accessTokens[new_access_token] = {
    client_id: client.client_id,
    user: storedRefreshToken.user,
    scope: tokenScope,
    expiresAt: Date.now() + (expires_in * 1000)
  };

  refreshTokens[new_refresh_token] = {
    client_id: client.client_id,
    user: storedRefreshToken.user,
    scope: tokenScope
  };

  res.set('Cache-Control', 'no-store');
  res.set('Pragma', 'no-cache');

  return res.json({
    access_token: new_access_token,
    token_type: 'Bearer',
    expires_in,
    refresh_token: new_refresh_token,
    scope: tokenScope
  });
}

// GET /userinfo - Protected resource (user info endpoint)
app.get('/userinfo', (req, res) => {
  const authHeader = req.headers['authorization'];
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({
      error: 'invalid_token',
      error_description: 'Access token is required. Use Authorization: Bearer <token>'
    });
  }

  const token = authHeader.slice(7);
  const tokenData = accessTokens[token];

  if (!tokenData) {
    return res.status(401).json({
      error: 'invalid_token',
      error_description: 'Invalid or expired access token'
    });
  }

  if (tokenData.expiresAt < Date.now()) {
    delete accessTokens[token];
    return res.status(401).json({
      error: 'invalid_token',
      error_description: 'Access token has expired'
    });
  }

  return res.json({
    sub: tokenData.user.username,
    name: tokenData.user.name,
    email: tokenData.user.email,
    scope: tokenData.scope
  });
});

// POST /token/introspect - Token introspection endpoint (RFC 7662)
app.post('/token/introspect', (req, res) => {
  // Authenticate the calling client
  let client_id, client_secret;
  const authHeader = req.headers['authorization'];
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.slice(6), 'base64').toString('utf-8');
    const parts = decoded.split(':');
    client_id = decodeURIComponent(parts[0]);
    client_secret = decodeURIComponent(parts.slice(1).join(':'));
  } else {
    client_id = req.body.client_id;
    client_secret = req.body.client_secret;
  }

  const client = clients[client_id];
  if (!client || client.client_secret !== client_secret) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Client authentication required'
    });
  }

  const { token, token_type_hint } = req.body;

  if (!token) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'token parameter is required'
    });
  }

  // Check access tokens
  const tokenData = accessTokens[token];
  if (tokenData && tokenData.expiresAt > Date.now()) {
    return res.json({
      active: true,
      scope: tokenData.scope,
      client_id: tokenData.client_id,
      username: tokenData.user.username,
      token_type: 'Bearer',
      exp: Math.floor(tokenData.expiresAt / 1000),
      iat: Math.floor((tokenData.expiresAt - 3600000) / 1000),
      sub: tokenData.user.username
    });
  }

  // Check refresh tokens
  const refreshData = refreshTokens[token];
  if (refreshData) {
    return res.json({
      active: true,
      scope: refreshData.scope,
      client_id: refreshData.client_id,
      username: refreshData.user.username,
      token_type: 'refresh_token',
      sub: refreshData.user.username
    });
  }

  // Token not found or expired
  return res.json({ active: false });
});

// POST /token/revoke - Token revocation endpoint (RFC 7009)
app.post('/token/revoke', (req, res) => {
  // Authenticate the calling client
  let client_id, client_secret;
  const authHeader = req.headers['authorization'];
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.slice(6), 'base64').toString('utf-8');
    const parts = decoded.split(':');
    client_id = decodeURIComponent(parts[0]);
    client_secret = decodeURIComponent(parts.slice(1).join(':'));
  } else {
    client_id = req.body.client_id;
    client_secret = req.body.client_secret;
  }

  const client = clients[client_id];
  if (!client || client.client_secret !== client_secret) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Client authentication required'
    });
  }

  const { token } = req.body;

  if (!token) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'token parameter is required'
    });
  }

  // Revoke access token if it exists and belongs to this client
  if (accessTokens[token]) {
    if (accessTokens[token].client_id === client_id) {
      delete accessTokens[token];
    }
  }

  // Revoke refresh token if it exists and belongs to this client
  if (refreshTokens[token]) {
    if (refreshTokens[token].client_id === client_id) {
      delete refreshTokens[token];
    }
  }

  // Always return 200 per RFC 7009
  return res.status(200).send();
});

